-- ----------------------------
-- Table structure for bet_records
-- ----------------------------
DROP TABLE IF EXISTS `bet_records`;
CREATE TABLE `bet_records` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `site_id` int NOT NULL COMMENT '站点ID',
  `site_code` varchar(50) NOT NULL COMMENT '站点代码',
  `agent_id` int NOT NULL COMMENT '代理id',
  `user_id` bigint unsigned NOT NULL COMMENT '用户ID',
  `username` varchar(100) NOT NULL COMMENT '用户名',
  `platform` varchar(50) NOT NULL COMMENT '游戏平台',
  `currency` varchar(10) NOT NULL DEFAULT 'PHP' COMMENT '币种',
  `game_id` int NOT NULL COMMENT '游戏ID',
  `game_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `game_type` varchar(30) DEFAULT NULL COMMENT '游戏类型',
  `order_no` varchar(100) NOT NULL COMMENT '订单号',
  `round_id` varchar(100) DEFAULT NULL COMMENT '局号/回合号',
  `bet_amount` decimal(18,6) NOT NULL DEFAULT '0.000000' COMMENT '投注金额',
  `win_amount` decimal(18,6) NOT NULL DEFAULT '0.000000' COMMENT '赢取金额',
  `valid_amount` decimal(18,6) NOT NULL DEFAULT '0.000000' COMMENT '有效投注金额',
  `net_amount` decimal(18,6) NOT NULL DEFAULT '0.000000' COMMENT '净输赢',
  `bet_time` datetime NOT NULL COMMENT '投注时间',
  `settle_time` datetime DEFAULT NULL COMMENT '结算时间',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态:0未结算,1已结算,2取消,3无效',
  `raw_data` json DEFAULT NULL COMMENT '原始数据JSON',
  `ch_sync_status` tinyint NOT NULL DEFAULT '0' COMMENT '0未同步,1成功,2失败',
  `task_id` bigint DEFAULT '0' COMMENT '同步任务ID',
  `ch_sync_at` datetime DEFAULT NULL COMMENT '同步时间',
  `ch_sync_error` varchar(255) DEFAULT NULL COMMENT '同步错误',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_site_platform_order` (`site_id`,`platform`,`order_no`),
  KEY `idx_site_game_time` (`site_id`,`platform`,`bet_time`),
  KEY `idx_user_time` (`user_id`,`bet_time`),
  KEY `idx_username` (`username`),
  KEY `idx_sync` (`ch_sync_status`),
  KEY `idx_task_id` (`task_id`),
  KEY `idx_site_user_time` (`site_id`,`user_id`,`bet_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='游戏注单表';

-- ----------------------------
-- Table structure for game_list
-- ----------------------------
DROP TABLE IF EXISTS `game_list`;
CREATE TABLE `game_list` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `site_id` int NOT NULL DEFAULT '0' COMMENT '商户id',
  `type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '游戏种类',
  `platform` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '平台',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '游戏名称',
  `alias_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '别名',
  `style` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '游戏类型',
  `img` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '游戏图片',
  `img1` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '游戏图片1',
  `device` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '设备',
  `vendor` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '提供方',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `language` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '语言',
  `hot` tinyint NOT NULL DEFAULT '0' COMMENT '热门',
  `recommend` tinyint NOT NULL DEFAULT '0' COMMENT '推荐',
  `like_num` int NOT NULL DEFAULT '0' COMMENT '喜欢数量',
  `is_new` tinyint NOT NULL DEFAULT '0' COMMENT '新的',
  `sort` int NOT NULL DEFAULT '0' COMMENT '排序大的靠前',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态0关闭1开启',
  `available` tinyint(1) NOT NULL DEFAULT '1' COMMENT '可用状态1可用2维护',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '新增时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `game_id` int NOT NULL DEFAULT '17',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_site_id_game_id_code` (`site_id`,`game_id`,`code`),
  UNIQUE KEY `uk_site_id_platform_code` (`site_id`,`platform`,`code`),
  KEY `game_list_code_name_index` (`code`,`name`),
  KEY `idx_gameid_status` (`game_id`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=1236 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='已接游戏列表';

-- ----------------------------
-- Records of game_list
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for mq_outbox
-- ----------------------------
DROP TABLE IF EXISTS `mq_outbox`;
CREATE TABLE `mq_outbox` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `event_type` varchar(64) NOT NULL COMMENT '事件类型，如 user_created / balance_transfer',
  `aggregate_type` varchar(64) NOT NULL COMMENT '聚合根类型，如 user / balance',
  `aggregate_id` varchar(64) NOT NULL COMMENT '聚合根ID，如 user_id / trade_no',
  `site_code` varchar(32) NOT NULL DEFAULT '' COMMENT '站点代码',
  `exchange` varchar(128) NOT NULL COMMENT 'MQ exchange',
  `routing_key` varchar(128) NOT NULL COMMENT 'MQ routing key',
  `payload` json NOT NULL COMMENT '发送到 MQ 的消息体',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态: 0=待发送, 1=已发送, 2=发送失败',
  `retry_count` int NOT NULL DEFAULT '0' COMMENT '重试次数',
  `next_retry_at` datetime DEFAULT NULL COMMENT '下次重试时间',
  `last_error` varchar(255) DEFAULT NULL COMMENT '最后一次发送错误信息',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_status_retry` (`status`,`next_retry_at`),
  KEY `idx_event` (`event_type`),
  KEY `idx_aggregate` (`aggregate_type`,`aggregate_id`),
  KEY `idx_site_code` (`site_code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='MQ Outbox 表（可靠消息）';

-- ----------------------------
-- Table structure for site_game
-- ----------------------------
DROP TABLE IF EXISTS `site_game`;
CREATE TABLE `site_game` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `site_id` int NOT NULL COMMENT '站点ID',
  `game_id` int NOT NULL DEFAULT '0' COMMENT '总站里游戏ID',
  `type` tinyint NOT NULL COMMENT '游戏类型。1=体育；2=彩票；3=真人；4=电子游戏',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '游戏名称',
  `platform` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '游戏平台',
  `image_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '游戏图片目录',
  `db_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '游戏对应数据表',
  `api_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'API_ID',
  `api_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'API_KEY',
  `api_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'API_URL',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '游戏是否打开或者或者关闭。1=打开；0=关闭',
  `sort` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1206 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='站点游戏表';

-- ----------------------------
-- Records of site_game
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for sync_tasks
-- ----------------------------
DROP TABLE IF EXISTS `sync_tasks`;
CREATE TABLE `sync_tasks` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `site_id` int NOT NULL COMMENT '站点ID',
  `site_code` varchar(50) NOT NULL COMMENT '站点代码',
  `platform` varchar(50) NOT NULL COMMENT '游戏平台',
  `task_type` tinyint NOT NULL COMMENT '任务类型: 1=定时拉单, 2=手动补单',
  `start_time` datetime NOT NULL COMMENT '拉单开始时间',
  `end_time` datetime NOT NULL COMMENT '拉单结束时间',
  `mysql_total` int NOT NULL DEFAULT '0' COMMENT 'MySQL总记录数',
  `mysql_inserted` int NOT NULL DEFAULT '0' COMMENT 'MySQL新插入数',
  `mysql_duplicated` int NOT NULL DEFAULT '0' COMMENT 'MySQL重复跳过数',
  `mq_sent` int NOT NULL DEFAULT '0' COMMENT 'MQ发送成功数',
  `mq_failed` int NOT NULL DEFAULT '0' COMMENT 'MQ发送失败数',
  `mq_skipped` int NOT NULL DEFAULT '0' COMMENT 'MQ跳过数(未结算或无user_id)',
  `ch_synced` int NOT NULL DEFAULT '0' COMMENT 'ClickHouse已同步数',
  `ch_failed` int NOT NULL DEFAULT '0' COMMENT 'ClickHouse同步失败数',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '任务状态: 1=进行中, 2=已完成, 3=失败',
  `error_msg` text COMMENT '错误信息',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `completed_at` datetime DEFAULT NULL COMMENT '完成时间',
  PRIMARY KEY (`id`),
  KEY `idx_site_platform` (`site_id`,`platform`),
  KEY `idx_site_code` (`site_code`),
  KEY `idx_task_type` (`task_type`),
  KEY `idx_status` (`status`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='同步任务表';

-- ----------------------------
-- Table structure for user_game_favorite
-- ----------------------------
DROP TABLE IF EXISTS `user_game_favorite`;
CREATE TABLE `user_game_favorite` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `site_id` int NOT NULL COMMENT '站点ID',
  `user_id` bigint unsigned NOT NULL COMMENT '用户ID',
  `platform` varchar(32) NOT NULL DEFAULT '' COMMENT '游戏平台，如 ONE',
  `game_code` varchar(64) NOT NULL DEFAULT '' COMMENT '游戏代码，如 JL_77',
  `game_id` int NOT NULL DEFAULT '0' COMMENT '游戏ID（可选冗余）',
  `game_name` varchar(128) NOT NULL DEFAULT '' COMMENT '游戏名称（冗余）',
  `vendor` varchar(32) NOT NULL DEFAULT '' COMMENT '厂商（冗余，如 JL）',
  `style` varchar(32) NOT NULL DEFAULT '' COMMENT '类型（冗余，如 SLOTS）',
  `game_img` varchar(512) NOT NULL DEFAULT '' COMMENT '游戏图片（冗余）',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_site_user_game` (`site_id`,`user_id`,`platform`,`game_code`),
  KEY `idx_site_user` (`site_id`,`user_id`),
  KEY `idx_site_platform_code` (`site_id`,`platform`,`game_code`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='用户游戏收藏表';

-- ----------------------------
-- Table structure for user_mapping
-- ----------------------------
DROP TABLE IF EXISTS `user_mapping`;
CREATE TABLE `user_mapping` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `site_id` int NOT NULL COMMENT '站点ID',
  `site_code` varchar(50) NOT NULL COMMENT '站点code',
  `username` varchar(128) NOT NULL COMMENT '游戏用户名（含site前缀）',
  `agent_id` int NOT NULL COMMENT '代理id',
  `user_id` bigint unsigned NOT NULL COMMENT '主系统用户ID',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_site_username` (`site_id`,`username`),
  KEY `idx_site_user` (`site_id`,`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='game服务-用户映射表';

SET FOREIGN_KEY_CHECKS = 1;
